import json

books = [
  {"id":1,"title":"Sapiens: Краткая история человечества","author":"Юваль Ной Харари","cover":"sapiens.jpg","world_reads":25000000,"world_reads_label":"25 млн+ копий","thoughts":[{"title":"Homo sapiens победил благодаря коллективным мифам","example":"Деньги, государства, религии — всё это коллективные фикции. Два незнакомца сотрудничают ради доллара или нации — потому что оба верят в одну историю. Ни один шимпанзе не рискнёт жизнью ради банкноты. Именно эта способность создавать разделяемые вымышленные реальности позволила нам организоваться в миллиардные общества."},{"title":"Аграрная революция — величайшее мошенничество истории","example":"12 000 лет назад люди начали выращивать пшеницу. Средний охотник работал 4-5 часов в день, ел разнообразно и почти не болел. Крестьянин работал 12 часов, ел однообразно и страдал от болезней. Пшеница не служила людям — люди служили пшенице."},{"title":"История не движется к прогрессу","example":"Мы думаем, что история идёт вперёд. Но Рим пал, уничтожив 600 лет достижений. Цивилизация майя исчезла. СССР распался. Нет исторического закона, гарантирующего рост."},{"title":"Деньги — самая успешная история человечества","example":"Золотая монета биологически бесполезна — её нельзя съесть. Но весь мир верит в её ценность. Именно так работает биткоин — та же вера, та же коллективная фикция. Разница: золоту 5000 лет доверия, биткоину — 15."},{"title":"Счастье не росло вместе с прогрессом","example":"Средний европеец 2024 года богаче короля Людовика XIV в тысячи раз. Но субъективное ощущение счастья почти не изменилось за 200 лет. Мы адаптируемся к любому уровню комфорта за 3-6 месяцев. Это называется гедонистическая адаптация."}]},
  {"id":2,"title":"Атомные привычки","author":"Джеймс Клир","cover":"atom.jpg","world_reads":20000000,"world_reads_label":"20 млн+ копий","thoughts":[{"title":"Улучшение на 1% каждый день — рост в 37 раз за год","example":"1,01 в степени 365 = 37,78. Велокоманда Великобритании улучшила каждый элемент подготовки на 1%: позу, питание, шины. Через 5 лет — золото Олимпиады и победа на Тур де Франс. До этого команда не выигрывала 110 лет."},{"title":"Система важнее цели","example":"Перед Олимпиадой каждый спортсмен хочет золото — цель одна у всех. Побеждает тот, у кого лучше система ежедневной подготовки. Цель задаёт направление, но не гарантирует результат."},{"title":"Меняй идентичность, а не только поведение","example":"Я пытаюсь бросить курить и Я не курю — это две разные личности. Первый борется с собой. Второй просто отказывается — это не его история. Начни с вопроса: каким человеком я хочу быть?"},{"title":"Правило двух минут: сделай начало лёгким","example":"Хочешь читать каждый вечер? Не читать 30 минут, а открыть книгу и прочитать одну страницу. Хочешь бегать? Не пробежать 5 км, а надеть кроссовки и выйти за дверь. 95% людей не бросают привычку на 10-й минуте — они не начинают вовсе."},{"title":"Среда формирует поведение сильнее воли","example":"В армии США во Вьетнаме 20% солдат употребляли героин. После возвращения домой 95% бросили без лечения — просто среда изменилась. В Голландии 38% поездок на велосипеде, в США 1%. Не потому что голландцы дисциплинированнее — у них везде велодорожки."}]},
  {"id":3,"title":"Голая обезьяна","author":"Десмонд Моррис","cover":"golaya.jpg","world_reads":12000000,"world_reads_label":"12 млн+ копий","thoughts":[{"title":"Человек — это голая обезьяна с претензиями","example":"Мы называем себя Homo sapiens — человек разумный. Но когда мужчина видит привлекательную женщину — срабатывают те же нейронные механизмы, что у самца шимпанзе. Когда начальник входит в комнату — все интуитивно чуть выпрямляются. Это не культура — это приматы."},{"title":"Иерархия — биологическая необходимость","example":"В каждой стае обезьян есть альфа. В каждом офисе есть неформальный лидер, к которому обращаются за решением. Статус в группе влияет на уровень кортизола, тестостерона, иммунитет. Низкоранговые особи болеют чаще — доказано и у приматов, и у людей."},{"title":"Сексуальные предпочтения заданы эволюцией","example":"Женщины во всех культурах предпочитают мужчин с признаками статуса и ресурсов. Мужчины — женщин с признаками молодости и здоровья. Это не патриархат — это 200 000 лет естественного отбора."},{"title":"Подросток курит из инстинкта стаи","example":"Подросток, впервые выкуривающий сигарету, не получает удовольствия — он задыхается. Но делает это, потому что сигарета — сигнал принадлежности к группе. Это древний механизм демонстрации лояльности стае."},{"title":"Ритуалы приветствия — язык безопасности","example":"Рукопожатие возникло как демонстрация пустой руки — у меня нет оружия. Объятие — мои руки не за спиной. Поцелуй — я подношу лицо близко и уязвимо. Все эти ритуалы — язык безопасности, которому миллионы лет."}]},
  {"id":4,"title":"Человек в поисках смысла","author":"Виктор Франкл","cover":"human.jpg","world_reads":16000000,"world_reads_label":"16 млн+ копий","thoughts":[{"title":"Последняя свобода — выбирать отношение к обстоятельствам","example":"В Освенциме у Франкла отняли всё: семью, имущество, имя. Но нацисты не могли управлять тем, как он интерпретирует происходящее внутри. Те, кто нашёл зачем — переносили любое как."},{"title":"Отсутствие смысла убивает быстрее болезней","example":"Заключённые, потерявшие веру в будущее, умирали в течение недель — даже если физически были сильнее других. Истощённые люди выживали, если у них было что-то незаконченное — ребёнок, которого надо увидеть, книга, которую надо дописать."},{"title":"Страдание теряет власть, когда обретает смысл","example":"К Франклу обратился врач, убитый горем после смерти жены. Франкл спросил: что было бы, если бы умерли вы? — Она бы так страдала. — Вы взяли её страдание на себя. Врач встал и ушёл. Боль не исчезла — но обрела смысл."},{"title":"Смысл можно найти в деле, в любви или в страдании","example":"Первый путь — через то, что создаём. Второй — через встречу с другим человеком. Третий — через позицию к неизбежному страданию. Нельзя выбрать болезнь, но можно выбрать достоинство, с которым её принимаешь."},{"title":"Счастье нельзя преследовать — оно побочный эффект","example":"Чем больше человек гонится за счастьем — тем дальше оно уходит. Франкл называет это гипер-интенцией. Счастье как сон: чем сильнее стараешься заснуть, тем дольше не спишь."}]},
  {"id":5,"title":"Думай медленно... решай быстро","author":"Даниэль Канеман","cover":"dumay.png","world_reads":10000000,"world_reads_label":"10 млн+ копий","thoughts":[{"title":"Система 1 и Система 2: два режима мышления","example":"Система 1 — быстрая, автоматическая, эмоциональная. Система 2 — медленная, аналитическая. Система 1 работает постоянно и незаметно принимает большинство решений. Когда вы покупаете акцию на эмоции — это Система 1 ведёт вас, пока Система 2 дремлет."},{"title":"Якорный эффект: первое число захватывает мозг","example":"Участников просили крутить рулетку (10 или 65) и угадывать процент африканских стран в ООН. Те, у кого выпало 65, называли в среднем 45%. У кого выпало 10 — 25%. Случайное число полностью исказило ответ."},{"title":"Потери бьют вдвое сильнее приобретений","example":"Потеря 10 000 рублей причиняет боль вдвое сильнее, чем радость от выигрыша тех же 10 000. Это неприятие потерь. Поэтому инвесторы держат убыточные акции — продать значит зафиксировать потерю, это невыносимо."},{"title":"Доступность эвристика: вероятность по яркости воспоминания","example":"После теракта скачок продаж страховок от терроризма — хотя вероятность не изменилась. Люди боятся акул больше коров — хотя коровы убивают в 20 раз чаще. Страшные события запоминаются ярко."},{"title":"Уверенность — враг точности","example":"Финансовые консультанты крупного банка: год за годом их рекомендации не превышали случайного выбора — при этом все были абсолютно уверены в своей экспертизе. Уверенность создаётся согласованностью нарратива, а не точностью анализа."}]},
  {"id":6,"title":"Сила привычки","author":"Чарлз Дахигг","cover":"sila.jpg","world_reads":5000000,"world_reads_label":"5 млн+ копий","thoughts":[{"title":"Петля привычки: сигнал — рутина — награда","example":"Хопкинс продвигал пасту Pepsodent. Сигнал: пощупай язык — чувствуешь налёт. Рутина: почисти зубы. Награда: покалывание во рту. Через 10 лет более половины американцев чистили зубы ежедневно. Без покалывания привычка не закрепилась бы."},{"title":"Нельзя уничтожить привычку — только заменить рутину","example":"Алкоголики в AA не учатся не пить — они меняют рутину при том же сигнале и той же награде. Сигнал: стресс. Старая рутина: выпить. Новая рутина: позвонить спонсору. Награда: снятие напряжения — та же."},{"title":"Ключевые привычки запускают цепную реакцию","example":"Семьи, начавшие готовить еду дома: через полгода дети лучше учились, больше читали, меньше смотрели ТВ. Родители не работали над этим специально. Приготовление ужина стало якорной привычкой."},{"title":"Сила воли — это мышца: она устаёт","example":"Израильские судьи рассматривали заявления о досрочном освобождении. Утром одобряли 65%. Перед обедом — 0%. После обеда снова 65%. Именно поэтому диеты срываются вечером."},{"title":"Организационные привычки определяют судьбу компаний","example":"Пожар в лондонском метро в 1987 году (31 погибший) произошёл из-за привычки не моя зона. Никто не сообщал о проблемах в чужом районе. Новый директор изменил одно: любой сотрудник мог остановить поезд без разрешения."}]},
  {"id":7,"title":"Чёрный лебедь","author":"Нассим Талеб","cover":"lebed.jpg","world_reads":3000000,"world_reads_label":"3 млн+ копий","thoughts":[{"title":"Чёрные лебеди управляют историей","example":"До 1697 года европейцы были убеждены: все лебеди белые. Одна экспедиция в Австралию — и убеждение рухнуло. Интернет, 11 сентября, COVID, распад СССР — никто не предсказал. Мы создаём логику там, где была случайность."},{"title":"Мы систематически недооцениваем роль случайности","example":"Нарратив нашей жизни — история успеха с причинами. Я стал богатым, потому что работал упорно. Но в кладбище неудачников — полно людей, работавших так же упорно. Они просто не написали книг."},{"title":"Жизнь не по нормальному распределению","example":"Рост людей подчиняется нормальному распределению: самый высокий в 3 раза выше среднего. Богатство — нет: состояние Илона Маска превышает медианное в миллионы раз. Единичные события перевешивают всё остальное."},{"title":"Стратегия: ограниченный риск, неограниченный выигрыш","example":"Компания Талеба делала небольшие ставки на маловероятные катастрофы. Когда рынок рухнул в 2008 году — выиграла полмиллиарда. 90% консервативно, 10% — на асимметричные ставки."},{"title":"Молчаливые свидетели: мы не видим тех, кто не выжил","example":"В Древнем Риме показывали портреты спасённых, молившихся Нептуну. Но портретов утонувших — кто тоже молился — не было. Мы видим Джобса, бросившего университет. Мы не видим 10 000 людей, бросивших университет и ставших никем."}]},
  {"id":8,"title":"Гении и аутсайдеры","author":"Малкольм Гладуэлл","cover":"genii.jpg","world_reads":2000000,"world_reads_label":"2 млн+ копий","thoughts":[{"title":"Правило 10 000 часов: мастерство — накопленная практика","example":"Моцарт написал первые значимые произведения в 21 год — после 18 лет практики с 3-х лет. Битлз до прорыва в США сыграли 1200 концертов в Гамбурге. Гейтс к 20 годам наиграл 10 000 часов программирования."},{"title":"Месяц рождения определяет карьеру","example":"В канадской хоккейной лиге непропорционально много рождённых в январе-марте. Ребёнок, рождённый 2 января, физически крупнее сверстника от 31 декабря. Его отбирают в лучшие команды — и к 18 годам преимущество становится реальным."},{"title":"Культурное наследие управляет поведением глубже интеллекта","example":"В авиации Южной Кореи в 1990-е было много катастроф. Вторые пилоты не могли прямо говорить капитанам об ошибках — культура уважения к старшим. Намекали уклончиво — самолёты разбивались."},{"title":"Успех — это несколько удач одновременно","example":"Билл Гейтс родился в 1955 году — идеальное время для IT. Учился в редкой школе с компьютером в 1968. Жил рядом с университетом с мейнфреймом. Каждое обстоятельство — везение. Вместе — катапульта."},{"title":"Препятствие может стать конкурентным преимуществом","example":"Непропорционально высокий процент успешных юристов и предпринимателей — дислексики. Дислексия заставила их развить компенсаторные навыки: убеждать, делегировать, нанимать. Ричард Брэнсон, Чарльз Шваб, Стивен Спилберг — дислексики."}]},
  {"id":9,"title":"Не рычите на собаку!","author":"Карен Прайор","cover":"sobaka.jpg","world_reads":2000000,"world_reads_label":"2 млн+ копий","thoughts":[{"title":"Положительное подкрепление работает с любым существом","example":"Прайор дрессировала дельфинов для ВМФ США — животных, которых нельзя наказать. Единственный инструмент — позитивное подкрепление. Метод сработал настолько хорошо, что затем Прайор применила те же принципы к людям — с теми же результатами."},{"title":"Наказание подавляет, но не учит новому","example":"Когда ребёнка ругают — он узнаёт, что делать нельзя. Но не узнаёт, что делать нужно. Наказание работает только в момент и требует постоянного присутствия надсмотрщика."},{"title":"Вы постоянно дрессируете окружающих — осознанно или нет","example":"Жена кричит на мужа, что не помогает. Муж помогает — крик прекращается. Оба подкрепили паттерн: жена — крик как инструмент, муж — помощь только как реакцию на крик. Теперь без крика он не помогает."},{"title":"Точный маркер момента важнее награды","example":"При дрессировке нельзя дать лакомство в точный момент — рука слишком медленная. Кликер решает: щелчок маркирует точное поведение. В управлении людьми мгновенная обратная связь работает лучше, чем ежегодная премия."},{"title":"Переменное подкрепление создаёт самые устойчивые привычки","example":"Игровые автоматы работают на переменном подкреплении — иногда выигрываешь, иногда нет. Этот режим создаёт самую сильную зависимость. Лайки в соцсетях работают так же. Это причина зависимости от телефона."}]},
  {"id":10,"title":"Антихрупкость","author":"Нассим Талеб","cover":"antihrupkost.png","world_reads":1500000,"world_reads_label":"1.5 млн+ копий","thoughts":[{"title":"Антихрупкость — третья категория после хрупкости и устойчивости","example":"Хрупкое — разбивается от удара (стекло). Устойчивое — не меняется (камень). Антихрупкое — становится сильнее от удара: мышца после тренировки, иммунная система после болезни, бизнес после кризиса."},{"title":"Попытка устранить волатильность создаёт хрупкость","example":"ФРС десятилетиями предотвращала небольшие рецессии. В результате накопились диспропорции — в 2008 году катастрофа. Дети, защищённые от всех трудностей, не развивают устойчивости. Первый реальный удар — катастрофа."},{"title":"Via negativa: важнее убрать, чем добавить","example":"Врач, убирающий вредное (сахар, алкоголь, стресс), добивается больше, чем добавляющий суперфуды. Если сомневаешься — не делай. Действие — это риск. Бездействие — часто мудрость."},{"title":"Штанга: крайний консерватизм плюс крайняя агрессивность","example":"90% капитала — в абсолютно безопасных инструментах. 10% — в высокорискованных асимметричных ставках. Никакого умеренного риска посередине. Средний риск — максимальная уязвимость."},{"title":"Опция — антихрупкая позиция","example":"Опция — это право, но не обязанность. Могу попробовать, и если не понравится — выйду. Максимальная потеря ограничена, выигрыш — нет. Именно поэтому предприниматели часто богатеют."}]},
  {"id":11,"title":"Одураченные случайностью","author":"Нассим Талеб","cover":"slu4ainost.jpg","world_reads":1000000,"world_reads_label":"1 млн+ копий","thoughts":[{"title":"Успешные люди часто просто счастливчики","example":"1000 трейдеров торгуют случайно. Через год у 500 будет прибыль. Через 5 лет у 31 будет пятилетняя история успеха. Им дадут интервью, напишут книги об их методе. Результат статистически неотличим от случайного."},{"title":"Мозг рождён видеть паттерны — даже там, где их нет","example":"Мозг выработал эту способность за миллионы лет: лучше увидеть несуществующего хищника в шуме листьев, чем пропустить реального. Поэтому мы видим лицо на Марсе и находим систему в случайных числах."},{"title":"Мы учимся у выживших — и не видим проигравших","example":"Все истории успеха написаны выжившими. Ни один разорившийся ресторатор не написал книгу. Мы учимся у победителей стратегиям, работающим в 5% случаев — и не знаем о 95% проигравших с теми же стратегиями."},{"title":"Краткосрочная и долгосрочная вероятности не совпадают","example":"Стратегия, работающая в 51% дней, может уничтожить капитал — если неудачные дни случаются вначале. Стратегия, теряющая деньги 9 лет из 10 и выигрывающая в 1 год — может быть прибыльной."},{"title":"Эмоции — плохой советчик в мире случайности","example":"Инвестор видит падение акции на 10% — боль потери вдвое сильнее, он продаёт. Акция восстанавливается. Видит что другие зарабатывают — покупает на пике. Каждое эмоциональное решение движет против математического оптимума."}]},
  {"id":12,"title":"Рискуя собственной шкурой","author":"Нассим Талеб","cover":"riskuya.png","world_reads":1000000,"world_reads_label":"1 млн+ копий","thoughts":[{"title":"Если советчик не рискует — его совет не стоит ничего","example":"Финансовый аналитик получает зарплату независимо от правильности прогнозов. Военный стратег планирует войну из кабинета. Врач рекомендует операцию без ответственности за неудачу. Система без личных рисков системно порождает плохие решения."},{"title":"Агентская проблема разрушает системы изнутри","example":"Менеджер банка получает бонус за краткосрочную прибыль. Риски реализуются через 5 лет — он уже в другом банке. Именно так была структурирована система ипотечных деривативов перед кризисом 2008 года."},{"title":"Локальное знание ценнее глобальных теорий","example":"Сапожник знает о клиентах то, что не знает экономический советник. Местный фермер знает о своей почве то, что не знает агроном из столицы. Люди, несущие последствия своих решений, принимают лучшие решения."},{"title":"Симметрия: получаешь выгоду — неси риск","example":"Тот, кто строит корабль и получает прибыль от торговли, должен плыть на нём же. Хаммурапи: строитель, чей дом убил хозяина, должен быть казнён. Когда выгода и риск у одного — он автоматически принимает лучшие решения."},{"title":"Маленькие потери сейчас защищают от катастрофы потом","example":"Лесные пожары нужны — они сжигают мёртвый лес. Подавление каждой рецессии вливанием денег создаёт диспропорции и в итоге — 2008 год."}]},
  {"id":13,"title":"Харизма. Язык телодвижений","author":"Аллан Пиз","cover":"harizma.jpg","world_reads":1000000,"world_reads_label":"1 млн+ копий","thoughts":[{"title":"80% информации при общении — невербальная","example":"Психолог Меграбян: 55% — язык тела, 38% — интонация, только 7% — слова. Когда начальник говорит всё нормально, но скрещивает руки — мозг слушателя верит телу, а не словам. Именно поэтому ложь так трудно скрыть."},{"title":"Зеркальное отражение создаёт доверие автоматически","example":"Когда двое хорошо ладят — они бессознательно синхронизируют позы, жесты, темп речи. Официанты, зеркалящие заказ клиента, получают чаевые на 70% больше — доказано экспериментально."},{"title":"Открытые жесты сигнализируют уверенность","example":"Занятие пространства — разведённые руки, широкий шаг, прямая спина — сигналы высокого ранга. 2 минуты в позе силы перед собеседованием снижают кортизол и повышают тестостерон — физически меняют биохимию тела."},{"title":"Рукопожатие — это первый переговорный акт","example":"Ладонь вниз — доминирование. Вверх — подчинение. Вертикальная — равенство. Это происходит в первые секунды — до первого слова — и формирует первичную иерархию разговора."},{"title":"Настоящая улыбка отличима от социальной","example":"Настоящая улыбка задействует круговую мышцу глаза — морщинки у глаз появляются непроизвольно. Социальная — только мышцы рта. Мозг распознаёт разницу за 17 миллисекунд — быстрее, чем сознание успевает обработать."}]},
  {"id":14,"title":"Красная таблетка","author":"Андрей Курпатов","cover":"tabletka.jpg","world_reads":500000,"world_reads_label":"500 тыс+ копий","thoughts":[{"title":"Мозг не отражает реальность — он конструирует её","example":"Когда вы смотрите на яблоко — мозг получает нечёткий сигнал от сетчатки и строит модель из прошлого опыта. 90% того, что видите — это галлюцинация, дополненная прошлым. Два человека смотрят на одну ситуацию и видят разное."},{"title":"Дефолт-система — главный потребитель энергии мозга","example":"Когда мозг отдыхает — включается дефолт-система: внутренний монолог, фантазии, переживание прошлого. Она создаёт большинство тревог и депрессий. Поэтому люди тянутся к телефону при малейшей паузе."},{"title":"Социальный инстинкт сильнее рационального мышления","example":"Что подумают люди парализует сильнее страха смерти. Публичных выступлений боятся больше смерти — мозг оценивает социальное отвержение как смертельную угрозу."},{"title":"Умный человек строит более изощрённые оправдания","example":"Система 1 принимает решение, Система 2 придумывает логическое объяснение постфактум. Чем умнее человек — тем более изощрённые оправдания он строит. Образованный попадает в интеллектуальные ловушки чаще необразованного."},{"title":"Счастье — побочный эффект правильно организованной жизни","example":"Мозг не создан для счастья — он создан для выживания. Счастье как постоянное состояние нейробиологически невозможно. Оно появляется как мимолётный побочный эффект правильно выстроенной жизни."}]},
  {"id":15,"title":"Психология стресса","author":"Роберт Сапольски","cover":"psihologia.jpg","world_reads":500000,"world_reads_label":"500 тыс+ копий","thoughts":[{"title":"Стресс создан для зебры, а мы используем его на налоги","example":"Зебра убегает от льва — полная мобилизация: адреналин, кортизол, остановка пищеварения. Через 10 минут стресс прошёл. Человек думает о долге по кредиту в 3 часа ночи — та же биохимия. Но угроза не заканчивается месяцами."},{"title":"Хронический стресс уменьшает гиппокамп","example":"Длительное воздействие кортизола уменьшает объём гиппокампа — нейроны гибнут. У людей с ПТСР и депрессией гиппокамп на 8-15% меньше нормы. При устранении стрессора гиппокамп частично восстанавливается."},{"title":"Ощущение контроля важнее самого контроля","example":"Две группы крыс получали удары током. Первая могла нажать рычаг — удар прекращался. Вторая — нет. У второй развились язвы, иммунодефицит и депрессия. Ощущение я могу повлиять — это буквально лекарство."},{"title":"Социальный статус влияет на здоровье сильнее дохода","example":"Исследования служащих в Британии: чем ниже должность — тем выше кортизол, тем хуже здоровье. Контролировалось по зарплате — только положение в иерархии определяло биологическое здоровье."},{"title":"Физические упражнения — лучшее средство от стресса","example":"30 минут аэробной нагрузки снижают кортизол, повышают BDNF, увеличивают объём гиппокампа. Это буквальное биохимическое воздействие, сравнимое с антидепрессантами, но без побочных эффектов."}]},
  {"id":16,"title":"Прочь из замкнутого круга","author":"Джеффри Янг, Джанет Клоско","cover":"krug.jpg","world_reads":500000,"world_reads_label":"500 тыс+ копий","thoughts":[{"title":"Схемы — это программы, написанные в детстве","example":"Ребёнка часто критиковали — формируется схема я дефективный. Взрослым он избегает близких отношений или находит партнёров, которые критикуют — это знакомо и подтверждает схему. Схема управляет жизнью десятилетиями."},{"title":"Мы ищем ситуации, подтверждающие наши схемы","example":"Человек со схемой меня бросят выбирает партнёров, которые действительно уходят. Не потому что мазохист — а потому что его привлекает знакомое. Тревожная ревность разрушает отношения и создаёт ту самую ситуацию, которой боялся."},{"title":"Три способа справиться со схемой — и все три её сохраняют","example":"Схема я дефективный: капитуляция — соглашаться с унижением. Избегание — не вступать в отношения. Гиперкомпенсация — стать идеальным перфекционистом. Все три — способы не встретиться со схемой."},{"title":"Здоровые отношения переписывают эмоциональную память","example":"Схема-терапия предлагает терапевту выполнять роль хорошего родителя — поддерживающего, не критикующего. Это опыт здорового отношения, переписывающий эмоциональную память."},{"title":"Техника: разговор с внутренним ребёнком","example":"Когда взрослый в панике из-за обычного конфликта — скорее всего говорит детская часть. Остановиться: какой возраст я сейчас чувствую? Это создаёт дистанцию между реакцией и осознанием."}]},
  {"id":17,"title":"Как начать новую жизнь в понедельник и не бросить во вторник","author":"Антон Петряков","cover":"zhizn_ponedelnik.jpg","world_reads":200000,"world_reads_label":"Бестселлер","thoughts":[{"title":"Проблема не в лени — а в запуске от эмоции вместо системы","example":"Большинство начинают с понедельника — после эмоционального всплеска хватит так жить. Эмоция — топливо на 2-3 дня. К среде мотивация испаряется. Изменения нужно строить на механике и структуре, а не на энтузиазме."},{"title":"Биологические основы лени: это защитный механизм мозга","example":"Мозг тратит 20% энергии при весе 2% от массы тела. Лень — это мозг, уклоняющийся от новых энергозатрат. Нужно работать с системой поощрений мозга, а не бороться с ленью напрямую — это как бороться с гравитацией."},{"title":"Маленькие победы строят нейронные пути","example":"Каждый раз, когда делаешь сложное и справляешься — мозг выделяет дофамин. 66 повторений в среднем нужно для формирования автоматической привычки. Начинай с задач настолько маленьких, что отказ от них был бы смешным."},{"title":"Окружение — самый мощный инструмент изменений","example":"Если пятеро ближайших друзей не занимаются спортом и не читают — вероятность что ты будешь делать это стремится к нулю. Найди сообщество, для которого желаемое поведение является нормой."},{"title":"Система важнее цели: что происходит когда цель достигнута","example":"Спортсмен, нацеленный на медаль, часто впадает в депрессию после её получения — цель исчезла. Человек, похудевший на 10 кг, через год набирает обратно — потому что целью была точка, а не процесс."}]},
  {"id":18,"title":"Как начать думать в понедельник и не перестать во вторник","author":"Антон Петряков","cover":"dumat_ponedelnik.jpg","world_reads":150000,"world_reads_label":"Бестселлер | Премия Здравомыслие 2021","thoughts":[{"title":"Критическое мышление — навык, а не врождённое качество","example":"Большинство убеждены, что мыслят рационально. Рациональное мышление включается только при специальном усилии. По умолчанию мы используем быстрые интуитивные эвристики, часто ошибочные."},{"title":"Когнитивные искажения работают против нас каждый день","example":"Эффект подтверждения: мы замечаем факты, подтверждающие то, во что верим, и игнорируем противоречащие. Инвестор, убеждённый в росте акции, замечает позитивные новости — до тех пор, пока не теряет деньги."},{"title":"Скорость информации обратно пропорциональна её качеству","example":"Сообщение в Telegram за 3 секунды содержит меньше смысла, чем книга за 8 часов. Мозг, привыкший к коротким форматам, теряет способность обрабатывать длинные аргументы. Это называется цифровая деменция."},{"title":"Вопросы важнее ответов","example":"Большинство образовательных систем учат запоминать ответы. Реальная жизнь требует умения задавать правильные вопросы. Почему я злюсь на этого человека важнее, чем что мне сделать с ним."},{"title":"Медленное мышление — конкурентное преимущество в мире скорости","example":"В мире, где все реагируют мгновенно — способность остановиться и подумать стала редкостью. Баффет принимает инвестиционные решения за несколько минут — после многолетнего анализа."}]},
  {"id":19,"title":"Быть нельзя казаться","author":"Антон Петряков","cover":"kazaca.jpg","world_reads":100000,"world_reads_label":"100 тыс+ копий","thoughts":[{"title":"Самообман — биологически обусловленный механизм выживания","example":"Люди, слегка завышающие самооценку, счастливее и успешнее реалистов. Проблема начинается, когда самообман становится глобальным: человек убеждён, что лучше и умнее всех — и эта иллюзия блокирует рост."},{"title":"Поддержание маски успешного съедает энергию","example":"Человек, постоянно поддерживающий образ сильного тратит огромную ментальную энергию на фасад. Синдром самозванца — прямое следствие разрыва между казаться и быть. Чем больше разрыв — тем сильнее тревога."},{"title":"Тревога часто следствие неосознанной лжи себе","example":"Человек жалуется на тревогу — при разборе выясняется, что годами живёт не своей жизнью и знает это, но не признаёт. Тревога — сигнал рассогласования между тем, кто ты есть, и кем притворяешься."},{"title":"Психологические защиты — способы избежать болезненной правды","example":"Рационализация: Я не получил повышение, потому что начальник меня недолюбливает вместо Я недостаточно компетентен. Проекция: Все завидуют вместо Я завидую. Все защищают от боли — но ценой остановки роста."},{"title":"Быть честным с собой — это практика, а не состояние","example":"Мозг защищает от болезненных истин. Но практика регулярного стоп — что я на самом деле чувствую, чего хочу — постепенно уменьшает слепые пятна. Дневник, терапия, честный собеседник — инструменты этой практики."}]},
  {"id":20,"title":"Не упускайте своих детей","author":"Гордон Ньюфелд, Габор Матэ","cover":"deti.jpg","world_reads":300000,"world_reads_label":"300 тыс+ копий","thoughts":[{"title":"Ориентация на сверстников вытесняет ориентацию на родителей","example":"100 лет назад дети проводили время с взрослыми — на ферме, в ремесле. Сейчас с 3 лет попадают в группы сверстников. Когда значимыми становятся сверстники — дети теряют защиту взрослого мира."},{"title":"Привязанность — это не избалованность, а биологическая потребность","example":"Детёнышей обезьян дали железную суррогатную мать с едой и мягкую без еды. Детёныши проводили с мягкой 23 часа в сутки. Потребность в привязанности сильнее потребности в пище."},{"title":"Дисциплина работает только через отношения","example":"Ребёнок, ориентированный на родителя, хочет быть хорошим в его глазах. Я расстроен тобой работает лучше любого наказания. Ребёнок, ориентированный на сверстников — наказания не работают."},{"title":"Слёзы и злость — это здоровые реакции адаптации","example":"Культура учит не плакать, быть сильным. Но слёзы — нейробиологический механизм интеграции фрустрации. Ребёнок, которому не дают плакать, не обрабатывает фрустрацию — она накапливается в агрессии или тревоге."},{"title":"Смартфон создал невиданный конкурент родительскому влиянию","example":"Смартфон даёт ребёнку постоянный доступ к сверстникам 24/7. Авторитет родителей конкурирует с тысячами сверстников и блогеров. Осознанное время с детьми должно перевешивать экранное — не запретами, а присутствием."}]},
  {"id":21,"title":"Социальный вид","author":"Мэтью Либерман","cover":"vid.jpg","world_reads":300000,"world_reads_label":"300 тыс+ копий","thoughts":[{"title":"Социальная боль обрабатывается тем же отделом, что физическая","example":"Когда человека отвергают в онлайн-игре незнакомые люди — активируется та же часть мозга, что при физической боли. Парацетамол снизил социальную боль так же, как физическую. Отвержение от группы в древности было равносильно смерти."},{"title":"В режиме покоя мозг думает о людях","example":"Дефолт-система постоянно моделирует других — их мысли, намерения, чувства. Социальное моделирование — самая важная мыслительная работа для выживания в группе. Мозг тренируется в понимании других, даже отдыхая."},{"title":"Потребность в связях так же базова, как голод","example":"Через несколько недель одиночного заключения у здоровых людей — галлюцинации, паранойя, депрессия. Одиночество увеличивает смертность как курение 15 сигарет в день. Это не метафора — это физиология."},{"title":"Зеркальные нейроны: мы чувствуем то, что чувствуют другие","example":"Когда видим как кто-то укалывает палец — активируются те же нейроны, что при нашей боли. Когда кто-то зевает — зеваем. Мы буквально симулируем состояние другого в собственном теле."},{"title":"Статус в группе — вопрос выживания для мозга","example":"Чем ниже должность служащего — тем выше кортизол, тем хуже здоровье. Контролировалось по зарплате — только иерархия определяла биологическое здоровье."}]},
  {"id":22,"title":"Узники ненависти","author":"Аарон Бэк","cover":"uzniki.jpg","world_reads":200000,"world_reads_label":"200 тыс+ копий","thoughts":[{"title":"Ненависть начинается с дегуманизации","example":"Прежде чем убить — нужно перестать видеть в жертве человека. Нацистская пропаганда называла евреев крысами. Геноцид в Руанде начался, когда тутси назвали тараканами. Как только мозг классифицирует существо как не такое — моральные тормоза отключаются."},{"title":"Примитивное чёрно-белое мышление предшествует насилию","example":"Все мужчины одинаковые, все эти люди такие — мышление без нюансов. Это мышление маленького ребёнка — хорошее или плохое. Под давлением злости взрослый регрессирует к этому типу мышления."},{"title":"Групповой нарциссизм опаснее индивидуального","example":"Нарциссичный человек реагирует яростью на критику. Группа, убеждённая в своей исключительности, ведёт себя так же. Разница между патриотизмом и шовинизмом — в наличии нарциссической ранимости."},{"title":"Конфликты длятся, потому что каждая сторона считает себя жертвой","example":"Израильтяне и палестинцы. Каждая сторона имеет нарратив виктимности — и он делает насилие ответным, справедливым. Ни один конфликт не может быть разрешён, пока каждая сторона видит себя только жертвой."},{"title":"КПТ работает с предрассудками так же, как с депрессией","example":"Оспаривание автоматических мыслей применимо к предрассудкам. При специальной работе человек учится замечать исключения и усложнять картину мира. Медленно, требует мотивации — но работает."}]},
  {"id":23,"title":"Иерархия. Твой ранг решает всё","author":"Роман Забейда","cover":"mybook.jpg","world_reads":0,"world_reads_label":"Новинка","thoughts":[{"title":"Мир построен на иерархии — 12% управляют жизнью 88%","example":"В любом коллективе, компании, стране — один человек принимает реальные решения, остальные исполняют. Это биологический закон — этология описывает те же иерархические структуры у всех социальных животных. Вопрос: ты в какой группе?"},{"title":"Ранг сигнализируется и считывается за доли секунды","example":"Два человека заходят в офис. У одного прямая спина, медленный уверенный шаг, спокойный взгляд. У другого — сутулые плечи, быстрые мелкие шаги, взгляд в пол. До первого слова все знают — кто выше рангом. Это считывается за 250 миллисекунд."},{"title":"Система 1 управляет 88% — кто понимает это, управляет людьми","example":"Реклама, политика, продажи работают с Системой 1. Скидка 50% только сегодня — срочность. Все ваши соседи уже купили — социальное доказательство. Тот, кто понимает эти механизмы, видит манипуляцию и может противостоять ей."},{"title":"Примативность — сколько в тебе обезьяны","example":"Высокопримативный человек реагирует импульсивно: оскорбили — ответил немедленно. Низкая примативность — способность сделать паузу между стимулом и реакцией. В этой паузе — свобода и высокий ранг."},{"title":"Ранг — это система, а не один навык","example":"Нельзя быть богатым, но слабым физически, неуверенным в общении и зависимым от алкоголя — и считаться человеком высокого ранга. Здоровое тело, устойчивая психика, навыки коммуникации, финансовая независимость — всё это части одной системы."}]}
]

